goal:
forall A B C AB ABC,
  {add A B AB} -> {add AB C ABC} ->
    exists BC, {add B C BC} /\ {add A BC ABC}

forall A B C AB ABC,
 {append A B AB} -> {append AB C ABC} ->
   exists BC, {append B C BC} /\ {append A BC ABC}

forall A1 A2 B1 B2 L K J, nabla x,
  ctxs L K J -> {K, pr1 x x |- pr1 (A1 x) (A2 x)} -> {K |- pr1 B1 B2} ->
         {K |- pr1 (A1 B1) (A2 B2)}

forall A B1 B2 L K J,
   ctxs L K J -> {K |- pr1 A B1} -> {K |- pr1 A B2} ->
        exists C, {K |- pr1 B1 C} /\ {K |- pr1 B2 C}

forall L E E' T T', nabla x,
  {L, of x T' |- of (E x) T} -> {L |- of E' T'} ->
    {L |- of (E E') T}

forall C D T T' S S', nabla x, ctx C D ->
  {D, sred x x |- sred (T x) (T' x)} -> {D |- sred S S'} ->
  {D |- sred (T S) (T' S')}

forall L R N U T S,
  ctx L -> {L |- of (abs R) S} -> {L |- ins* S (arr U T)} ->
  {L |- of N U} -> {L |- of (R N) T}

forall L M N B,
  ctx L -> {L |- of (app M N) B} ->
    exists A, {L |- of M (arrow A B)} /\ {L |- of N A}

forall L M A B,
  ctx L -> {L |- of (abs A M) B} ->
    exists C, B = arrow A C /\ {ty A} /\ nabla x, {L, of x A  |- of (M x) C}

forall L K C,
  {form K} -> ctx L ->
    {L |- conc K} -> {L, hyp K |- conc C} -> {L |- conc C}

forall L J K A B,
  ctxs L J K ->
  {K, hil A |- hil B} -> {K |- hil (imp A B)}

forall L J K B B',
  ctxs L J K ->
  fold K B B' -> {K |- hil B} -> {hil B'}

forall M N L, nabla x y,
  {L, copy x y |- copy (M x) (N y)} ->
    nabla z, {L, copy z z |- copy (M z) (N z)}

forall N1 N2 N,
  {sum N1 N2 N} ->
    {natural N1} /\ {natural N2} /\ {natural N}

forall E V E',
  sexp nil E -> force nil E E' -> ees E V ->
    exists V', force nil V V' /\ {eval E' V'}

forall S1 S2 T1 T2,
  {sub (all S1 S2) (all T1 T2)} ->
    {sub T1 S1} /\ nabla x, {sub x T1 |- sub (S2 x) (T2 x)}

forall G SS D E,
  ofsub G SS D -> member E SS ->
  exists X M T, E = cp X M /\ member (of X T) D /\ name X /\ {G |- of M T}

forall G SS D E,
  ofsub G SS D -> member E D ->
  exists X M T, E = of X T /\ member (cp X M) SS /\ name X /\ {G |- of M T}

forall G SS D M T,
  ofsub G SS D -> {D |- of M T} ->
  exists SM, {SS |- cp M SM} /\ {G |- of SM T}

forall G SS D TT W UU M N K T,
  ofsub G SS D -> ofsub D TT W -> comp SS TT UU ->
  {W |- of M T} -> {TT |- cp M N} -> {SS |- cp N K} -> {UU |- cp M K}
